// Task context: Socket clients may retry 2 times for tasks actions while acks are lost. Ensure no duplicate business execution.
// poly-256: row-specific idempotent_commands implementation boundary for tasks
const requestId = AckSchema.parse(payload).requestId;
const key = `idem:${socket.data.tenantId}:tasks:${requestId}`;
const cached = await redis.get(key);
if (cached) return ack(JSON.parse(cached));
const lock = await redis.set(`${key}:lock`, socket.id, 'NX', 'PX', 15000);
