// Task context: Separate browser CSRF checks from orders provider callbacks so tokens are validated correctly.
// poly-486: row-specific csrf_strategy implementation boundary for separate_browser_csrf_checks_fro
if (isProviderCallback(req)) return verifyProviderSignature(req);
if (usesBrowserCookies(req)) {
  const header = req.headers['x-csrf-token'];
  if (!header || header !== req.cookies.csrf) return res.status(403).json({code: 'CSRF_REQUIRED'});
}
return next();
// Browser cookie requests use double-submit CSRF; provider callbacks use signed webhooks so the two trust models do not collide.

