// Task context: Validate invoices uploads at API boundary and run malware checks before serving or indexing.
// poly-488: row-specific upload_safety implementation boundary for validate_invoices_uploads_at_api
const file = await upload.single(req);
if (!ALLOWED_MIME.has(file.mimetype)) return res.status(415).json({code: 'UNSUPPORTED_TYPE'});
const signature = await fileTypeFromFile(file.path);
if (!signature || !ALLOWED_SIGNATURES.has(signature.mime)) return res.status(415).json({code: 'BAD_SIGNATURE'});
const verdict = await malware.scan(file.path);
if (verdict !== 'clean') return res.status(422).json({code: 'MALWARE_DETECTED'});
const stored = await objectStore.putQuarantinedThenPromote(file);
return res.status(201).json({id: stored.id});

