// Task context: Socket clients may retry 5 times for profiles actions while acks are lost. Ensure no duplicate business execution.
// poly-499: row-specific idempotent_commands implementation boundary for profiles
const requestId = AckSchema.parse(payload).requestId;
const key = `idem:${socket.data.tenantId}:profiles:${requestId}`;
const cached = await redis.get(key);
if (cached) return ack(JSON.parse(cached));
const lock = await redis.set(`${key}:lock`, socket.id, 'NX', 'PX', 15000);
if (!lock) return ack({status: 202, code: 'IN_PROGRESS'});
try {
  const result = await service.executeProfiles(payload, {tenantId: socket.data.tenantId, requestId});
  await redis.set(key, JSON.stringify(result), 'EX', 86400);
  return ack(result);
} finally { await redis.del(`${key}:lock`); }

// Task context: Prevent two workers from simultaneously finalizing the same reviews resource under bursty queue retries.
// poly-500: row-specific distributed_lock implementation boundary for prevent_two_workers_from_simulta
const token = crypto.randomUUID();
const lockKey = `lock:records:${payload.id}`;
if (!(await redis.set(lockKey, token, 'NX', 'PX', 10000))) return {status: 409, code: 'LOCKED'};
try {
  return await db.$transaction(async (tx) => {
    const current = await tx.records.findUniqueOrThrow({where: {id: payload.id}});
    if (current.state !== 'pending') return {status: 409, code: 'INVALID_STATE'};
    await tx.records.update({where: {id: payload.id}, data: {state: 'finalized', finalizedAt: new Date()}});
    return {status: 200};
  });
} finally {
  await redis.eval("if redis.call('GET', KEYS[1]) == ARGV[1] then return redis.call('DEL', KEYS[1]) end", 1, lockKey, token);
}
